  1	import React, { FC, useMemo, useState } from 'react';
  2	import { Link } from 'react-router-dom-v5-compat';
  3	import produce from 'immer';
  4	import { isDedicatedCPUPlacement } from 'src/views/templates/utils/utils';
  5	
  6	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes';
  7	import {
  8	  cpuManagerLabel,
  9	  cpuManagerLabelKey,
 10	  cpuManagerLabelValue,
 11	} from '@kubevirt-utils/components/DedicatedResourcesModal/utils/constants';
 12	import Loading from '@kubevirt-utils/components/Loading/Loading';
 13	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 14	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 15	import { modelToGroupVersionKind, NodeModel, V1Template } from '@kubevirt-utils/models';
 16	import { getTemplateVirtualMachineObject } from '@kubevirt-utils/resources/template';
 17	import { ensurePath, isEmpty } from '@kubevirt-utils/utils/utils';
 18	import { ResourceLink, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 19	import {
 20	  Alert,
 21	  AlertVariant,
 22	  Button,
 23	  Checkbox,
 24	  Form,
 25	  FormGroup,
 26	  Label,
 27	  Popover,
 28	} from '@patternfly/react-core';
 29	
 30	type DedicatedResourcesModalProps = {
 31	  isOpen: boolean;
 32	  onClose: () => void;
 33	  onSubmit: (updatedTemplate: V1Template) => Promise<V1Template | void>;
 34	  template: V1Template;
 35	};
 36	
 37	const DedicatedResourcesModal: FC<DedicatedResourcesModalProps> = ({
 38	  isOpen,
 39	  onClose,
 40	  onSubmit,
 41	  template,
 42	}) => {
 43	  const { t } = useKubevirtTranslation();
 44	  const [checked, setChecked] = useState<boolean>(isDedicatedCPUPlacement(template));
 45	  const [nodes, nodesLoaded, loadError] = useK8sWatchResource<IoK8sApiCoreV1Node[]>({
 46	    groupVersionKind: modelToGroupVersionKind(NodeModel),
 47	    isList: true,
 48	  });
 49	
 50	  const { hasNodes, qualifiedNodes } = useMemo(() => {
 51	    const filteredNodes = nodes?.filter(
 52	      (node) => node?.metadata?.labels?.[cpuManagerLabelKey] === cpuManagerLabelValue,
 53	    );
 54	    return {
 55	      hasNodes: !!filteredNodes?.length,
 56	      qualifiedNodes: filteredNodes,
 57	    };
 58	  }, [nodes]);
 59	
 60	  const updatedTemplate = useMemo(() => {
 61	    return produce<V1Template>(template, (templateDraft: V1Template) => {
 62	      const draftVM = getTemplateVirtualMachineObject(templateDraft);
 63	      ensurePath(draftVM, ['spec.template.spec.domain.cpu']);
 64	      draftVM.spec.template.spec.domain.cpu.dedicatedCpuPlacement = checked;
 65	    });
 66	  }, [checked, template]);
 67	
 68	  return (
 69	    <TabModal
 70	      headerText={t('Dedicated resources')}
 71	      isOpen={isOpen}
 72	      obj={updatedTemplate}
 73	      onClose={onClose}
 74	      onSubmit={onSubmit}
 75	    >
 76	      <Form>
 77	        <FormGroup fieldId="dedicated-resources" isInline>
 78	          <Checkbox
 79	            description={
 80	              <>
 81	                {t('Available only on Nodes with labels')}{' '}
 82	                <Label color="purple" variant="filled">
 83	                  {!isEmpty(nodes) ? (
 84	                    <Link
 85	                      target="_blank"
 86	                      to={`/search?kind=${NodeModel.kind}&q=${encodeURIComponent(cpuManagerLabel)}`}
 87	                    >
 88	                      {cpuManagerLabel}
 89	                    </Link>
 90	                  ) : (
 91	                    cpuManagerLabel
 92	                  )}
 93	                </Label>
 94	              </>
 95	            }
 96	            id="dedicated-resources"
 97	            isChecked={checked}
 98	            label={t('Schedule this workload with dedicated resources (guaranteed policy)')}
 99	            onChange={(_, check: boolean) => setChecked(check)}
100	          />
101	        </FormGroup>
102	        <FormGroup fieldId="dedicated-resources-node">
103	          {!isEmpty(nodes) ? (
104	            <Alert
105	              title={
106	                hasNodes
107	                  ? t('{{qualifiedNodesCount}} matching nodes found', {
108	                      qualifiedNodesCount: qualifiedNodes?.length,
109	                    })
110	                  : t('No matching nodes found for the {{cpuManagerLabel}} label', {
111	                      cpuManagerLabel,
112	                    })
113	              }
114	              isInline
115	              variant={hasNodes ? AlertVariant.success : AlertVariant.warning}
116	            >
117	              {hasNodes ? (
118	                <Popover
119	                  bodyContent={
120	                    <>
121	                      {qualifiedNodes?.map((node) => (
122	                        <ResourceLink
123	                          groupVersionKind={modelToGroupVersionKind(NodeModel)}
124	                          key={node.metadata.uid}
125	                          name={node.metadata.name}
126	                        />
127	                      ))}
128	                    </>
129	                  }
130	                  headerContent={t('{{qualifiedNodesCount}} nodes found', {
131	                    qualifiedNodesCount: qualifiedNodes?.length,
132	                  })}
133	                >
134	                  <Button isInline onClick={() => setChecked(false)} variant="link">
135	                    {t('view {{qualifiedNodesCount}} matching nodes', {
136	                      qualifiedNodesCount: qualifiedNodes?.length,
137	                    })}
138	                  </Button>
139	                </Popover>
140	              ) : (
141	                t('Scheduling will not be possible at this state')
142	              )}
143	            </Alert>
144	          ) : (
145	            !loadError && !nodesLoaded && <Loading />
146	          )}
147	        </FormGroup>
148	      </Form>
149	    </TabModal>
150	  );
151	};
152	
153	export default DedicatedResourcesModal;

